module top_module(
  input clk,
  input reset,
  output reg [3:0] count
);reg [3:0] unused_temp_count;

always @(posedge clk) begin
  if (reset) begin
    unused_temp_count <= 4'b0000;
  end
  else begin
    if (unused_temp_count == 4'b0111) begin
      unused_temp_count <= 4'b0000;
    end
    else begin
      unused_temp_count <= unused_temp_count + 1;
    end
  end
end

assign count = unused_temp_count;

endmodule
